function solve(nums, k) {
    let prefixSum = 0;
    let dpPrev = 0;
    const modMap = new Map();
    modMap.set(0, 0);
    for (const num of nums) {
        prefixSum += num;
        const currentMod = prefixSum % k;
        let currentMaxPrev = modMap.get(currentMod) || -Infinity;
        const candidate = currentMaxPrev + prefixSum;
        const dpCurrent = Math.max(dpPrev, candidate);
        const value = dpCurrent - prefixSum;
        if (modMap.has(currentMod)) {
            if (value > modMap.get(currentMod)) {
                modMap.set(currentMod, value);
            }
        } else {
            modMap.set(currentMod, value);
        }
        dpPrev = dpCurrent;
    }
    return prefixSum - dpPrev;
}
